import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {
    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String directory = "/path/to/directory/";

        // Sanitize user input to prevent directory traversal
        String sanitizedUserInput = userInput.replace("..", "").replace("/", "");

        String filePath = directory + sanitizedUserInput;

        try {
            // Check if the file path is within the allowed directory
            if (filePath.startsWith(directory)) {
                File file = new File(filePath);
                FileInputStream fis = new FileInputStream(file);

                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }

                fis.close();
            } else {
                System.out.println("Access to specified path is not allowed.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

